  1→use std::{collections::HashMap, time::Instant};
  2→
  3→#[derive(Debug, thiserror::Error)]
  4→pub enum Error {
  5→    #[error("node not found")]
  6→    NodeNotFound,
  7→}
  8→
  9→pub type Result<T> = std::result::Result<T, Error>;
 10→
 11→/// A provider discovered on a remote node.
 12→#[derive(Debug, Clone)]
 13→pub struct NodeProviderEntry {
 14→    pub provider: String,
 15→    pub models: Vec<String>,
 16→}
 17→
 18→/// A connected device node (macOS, iOS, Android).
 19→#[derive(Debug, Clone)]
 20→pub struct NodeSession {
 21→    pub node_id: String,
 22→    pub conn_id: String,
 23→    pub display_name: Option<String>,
 24→    pub platform: String,
 25→    pub version: String,
 26→    pub capabilities: Vec<String>,
 27→    pub commands: Vec<String>,
 28→    pub permissions: HashMap<String, bool>,
 29→    pub path_env: Option<String>,
 30→    pub remote_ip: Option<String>,
 31→    pub connected_at: Instant,
 32→    // ── Telemetry fields (updated by node.telemetry events) ──────────
 33→    pub mem_total: Option<u64>,
 34→    pub mem_available: Option<u64>,
 35→    pub cpu_count: Option<u32>,
 36→    pub cpu_usage: Option<f32>,
 37→    pub uptime_secs: Option<u64>,
 38→    pub services: Vec<String>,
 39→    pub last_telemetry: Option<Instant>,
 40→    // ── Extended telemetry (P1) ──────────────────────────────────────
 41→    pub disk_total: Option<u64>,
 42→    pub disk_available: Option<u64>,
 43→    pub runtimes: Vec<String>,
 44→    // ── Provider discovery (P1) ─────────────────────────────────────
 45→    pub providers: Vec<NodeProviderEntry>,
 46→}
 47→
 48→/// Registry of connected device nodes and their capabilities.
 49→pub struct NodeRegistry {
 50→    /// node_id → NodeSession
 51→    nodes: HashMap<String, NodeSession>,
 52→    /// conn_id → node_id (reverse lookup for cleanup on disconnect)
 53→    by_conn: HashMap<String, String>,
 54→}
 55→
 56→impl Default for NodeRegistry {
 57→    fn default() -> Self {
 58→        Self::new()
 59→    }
 60→}
 61→
 62→impl NodeRegistry {
 63→    pub fn new() -> Self {
 64→        Self {
 65→            nodes: HashMap::new(),
 66→            by_conn: HashMap::new(),
 67→        }
 68→    }
 69→
 70→    pub fn register(&mut self, session: NodeSession) {
 71→        self.by_conn
 72→            .insert(session.conn_id.clone(), session.node_id.clone());
 73→        self.nodes.insert(session.node_id.clone(), session);
 74→    }
 75→
 76→    pub fn unregister_by_conn(&mut self, conn_id: &str) -> Option<NodeSession> {
 77→        let node_id = self.by_conn.remove(conn_id)?;
 78→        self.nodes.remove(&node_id)
 79→    }
 80→
 81→    pub fn get(&self, node_id: &str) -> Option<&NodeSession> {
 82→        self.nodes.get(node_id)
 83→    }
 84→
 85→    pub fn get_mut(&mut self, node_id: &str) -> Option<&mut NodeSession> {
 86→        self.nodes.get_mut(node_id)
 87→    }
 88→
 89→    pub fn list(&self) -> Vec<&NodeSession> {
 90→        self.nodes.values().collect()
 91→    }
 92→
 93→    pub fn has_mobile_node(&self) -> bool {
 94→        self.nodes
 95→            .values()
 96→            .any(|n| n.platform == "ios" || n.platform == "android")
 97→    }
 98→
 99→    pub fn rename(&mut self, node_id: &str, display_name: &str) -> Result<()> {
100→        let node = self.nodes.get_mut(node_id).ok_or(Error::NodeNotFound)?;
101→        node.display_name = Some(display_name.to_string());
102→        Ok(())
103→    }
104→
105→    /// Update telemetry data for a node.
106→    pub fn update_telemetry(
107→        &mut self,
108→        node_id: &str,
109→        mem_total: Option<u64>,
110→        mem_available: Option<u64>,
111→        cpu_count: Option<u32>,
112→        cpu_usage: Option<f32>,
113→        uptime_secs: Option<u64>,
114→        services: Vec<String>,
115→        disk_total: Option<u64>,
116→        disk_available: Option<u64>,
117→        runtimes: Vec<String>,
118→    ) -> Result<()> {
119→        let node = self.nodes.get_mut(node_id).ok_or(Error::NodeNotFound)?;
120→        node.mem_total = mem_total;
121→        node.mem_available = mem_available;
122→        node.cpu_count = cpu_count;
123→        node.cpu_usage = cpu_usage;
124→        node.uptime_secs = uptime_secs;
125→        node.services = services;
126→        node.disk_total = disk_total;
127→        node.disk_available = disk_available;
128→        node.runtimes = runtimes;
129→        node.last_telemetry = Some(Instant::now());
130→        Ok(())
131→    }
132→
133→    /// Remove all nodes (used when disconnecting all clients).
134→    pub fn clear(&mut self) {
135→        self.nodes.clear();
136→        self.by_conn.clear();
137→    }
138→
139→    pub fn count(&self) -> usize {
140→        self.nodes.len()
141→    }
142→}
