138→pub(super) fn register(reg: &mut MethodRegistry) {
139→    // node.list
140→    reg.register(
141→        "node.list",
142→        Box::new(|ctx| {
143→            Box::pin(async move {
144→                let inner = ctx.state.inner.read().await;
145→                let mut list: Vec<_> = inner
146→                    .nodes
147→                    .list()
148→                    .iter()
149→                    .map(|n| {
150→                        serde_json::json!({
151→                            "nodeId": n.node_id,
152→                            "displayName": n.display_name,
153→                            "platform": n.platform,
154→                            "version": n.version,
155→                            "capabilities": n.capabilities,
156→                            "commands": n.commands,
157→                            "remoteIp": n.remote_ip,
158→                            "telemetry": {
159→                                "memTotal": n.mem_total,
160→                                "memAvailable": n.mem_available,
161→                                "cpuCount": n.cpu_count,
162→                                "cpuUsage": n.cpu_usage,
163→                                "uptimeSecs": n.uptime_secs,
164→                                "services": n.services,
165→                                "diskTotal": n.disk_total,
166→                                "diskAvailable": n.disk_available,
167→                                "runtimes": n.runtimes,
168→                                "stale": n.last_telemetry.is_some_and(
169→                                    |t| t.elapsed() > Duration::from_secs(120),
170→                                ),
171→                            },
172→                            "providers": n.providers.iter().map(|p| {
173→                                serde_json::json!({
174→                                    "provider": p.provider,
175→                                    "models": p.models,
176→                                })
177→                            }).collect::<Vec<_>>(),
178→                        })
179→                    })
180→                    .collect();
181→                drop(inner);
182→                if let Some(store) = ctx.state.credential_store.as_ref() {
183→                    match store.list_ssh_targets().await {
184→                        Ok(targets) => {
185→                            for target in targets {
186→                                list.push(ssh_target_summary_json(&target));
187→                            }
188→                        },
189→                        Err(error) => tracing::warn!(%error, "failed to list managed ssh targets"),
190→                    }
191→                }
192→                if let Some(target) = configured_legacy_ssh_target() {
193→                    list.push(ssh_summary_json(&target));
194→                }
195→                Ok(serde_json::json!(list))
196→            })
197→        }),
198→    );
199→
200→    // node.describe
201→    reg.register(
202→        "node.describe",
203→        Box::new(|ctx| {
204→            Box::pin(async move {
205→                let node_id = ctx
206→                    .params
207→                    .get("nodeId")
208→                    .and_then(|v| v.as_str())
209→                    .ok_or_else(|| {
210→                        ErrorShape::new(error_codes::INVALID_REQUEST, "missing nodeId")
211→                    })?;
212→                if let Some(store) = ctx.state.credential_store.as_ref() {
213→                    match store.resolve_ssh_target(node_id).await {
214→                        Ok(Some(target)) => return Ok(ssh_target_detail_json(&target)),
215→                        Ok(None) => {},
216→                        Err(error) => {
217→                            tracing::warn!(%error, node_id, "failed to resolve managed ssh target")
218→                        },
219→                    }
220→                }
221→                if let Some(target) = configured_legacy_ssh_target()
222→                    && crate::node_exec::ssh_target_matches(node_id, &target)
223→                {
224→                    return Ok(ssh_detail_json(&target));
225→                }
226→                let inner = ctx.state.inner.read().await;
227→                let node = inner
228→                    .nodes
229→                    .get(node_id)
230→                    .ok_or_else(|| ErrorShape::new(error_codes::UNAVAILABLE, "node not found"))?;
231→                Ok(serde_json::json!({
232→                    "nodeId": node.node_id,
233→                    "displayName": node.display_name,
234→                    "platform": node.platform,
235→                    "version": node.version,
236→                    "capabilities": node.capabilities,
237→                    "commands": node.commands,
238→                    "permissions": node.permissions,
239→                    "pathEnv": node.path_env,
240→                    "remoteIp": node.remote_ip,
241→                    "connectedAt": node.connected_at.elapsed().as_secs(),
242→                    "telemetry": {
243→                        "memTotal": node.mem_total,
244→                        "memAvailable": node.mem_available,
245→                        "cpuCount": node.cpu_count,
246→                        "cpuUsage": node.cpu_usage,
247→                        "uptimeSecs": node.uptime_secs,
248→                        "services": node.services,
249→                        "diskTotal": node.disk_total,
250→                        "diskAvailable": node.disk_available,
251→                        "runtimes": node.runtimes,
252→                        "stale": node.last_telemetry.is_some_and(
253→                            |t| t.elapsed() > Duration::from_secs(120),
254→                        ),
255→                    },
256→                    "providers": node.providers.iter().map(|p| {
257→                        serde_json::json!({
258→                            "provider": p.provider,
259→                            "models": p.models,
260→                        })
261→                    }).collect::<Vec<_>>(),
262→                }))
263→            })
264→        }),
265→    );
266→
267→    // node.rename
268→    reg.register(
269→        "node.rename",
270→        Box::new(|ctx| {
271→            Box::pin(async move {
272→                let node_id = ctx
273→                    .params
274→                    .get("nodeId")
275→                    .and_then(|v| v.as_str())
276→                    .ok_or_else(|| {
277→                        ErrorShape::new(error_codes::INVALID_REQUEST, "missing nodeId")
278→                    })?;
279→                let name = ctx
280→                    .params
281→                    .get("displayName")
282→                    .and_then(|v| v.as_str())
283→                    .ok_or_else(|| {
284→                        ErrorShape::new(error_codes::INVALID_REQUEST, "missing displayName")
285→                    })?;
286→                let mut inner = ctx.state.inner.write().await;
287→                inner
288→                    .nodes
289→                    .rename(node_id, name)
290→                    .map_err(|e| ErrorShape::new(error_codes::UNAVAILABLE, e.to_string()))?;
291→                Ok(serde_json::json!({}))
292→            })
293→        }),
294→    );
295→
296→    // nodes.set_session: assign a node to a chat session
297→    reg.register(
298→        "nodes.set_session",
299→        Box::new(|ctx| {
300→            Box::pin(async move {
301→                let session_key = ctx
302→                    .params
303→                    .get("session_key")
304→                    .and_then(|v| v.as_str())
305→                    .ok_or_else(|| {
306→                        ErrorShape::new(
307→                            error_codes::INVALID_REQUEST,
308→                            "missing 'session_key' parameter",
309→                        )
310→                    })?;
311→                // node_id can be null to clear the node assignment.
312→                let node_id = ctx.params.get("node_id").and_then(|v| v.as_str());
313→                let resolved_node_id = if let Some(nid) = node_id {
314→                    if let Some(store) = ctx.state.credential_store.as_ref()
315→                        && let Some(target) = store
316→                            .resolve_ssh_target(nid)
317→                            .await
318→                            .map_err(|e| ErrorShape::new(error_codes::UNAVAILABLE, e.to_string()))?
319→                    {
320→                        Some(target.node_id)
321→                    } else if let Some(target) = configured_legacy_ssh_target()
322→                        && crate::node_exec::ssh_target_matches(nid, &target)
323→                    {
324→                        Some(crate::node_exec::ssh_node_id(&target))
325→                    } else {
326→                        let inner = ctx.state.inner.read().await;
327→                        if inner.nodes.get(nid).is_none() {
328→                            return Err(ErrorShape::new(
329→                                error_codes::INVALID_REQUEST,
330→                                format!("node '{nid}' not found or not connected"),
331→                            ));
332→                        }
333→                        Some(nid.to_string())
334→                    }
335→                } else {
336→                    None
337→                };
338→
339→                let Some(ref meta) = ctx.state.services.session_metadata else {
340→                    return Err(ErrorShape::new(
341→                        error_codes::UNAVAILABLE,
342→                        "session metadata not available",
343→                    ));
344→                };
345→                meta.upsert(session_key, None)
346→                    .await
347→                    .map_err(|e| ErrorShape::new(error_codes::UNAVAILABLE, e.to_string()))?;
348→                meta.set_node_id(session_key, resolved_node_id.as_deref())
349→                    .await
350→                    .map_err(|e| ErrorShape::new(error_codes::UNAVAILABLE, e.to_string()))?;
351→                Ok(serde_json::json!({ "ok": true, "node_id": resolved_node_id }))
352→            })
353→        }),
354→    );
355→
356→    // node.invoke: forward an RPC request to a connected node
357→    reg.register(
358→        "node.invoke",
359→        Box::new(|ctx| {
360→            Box::pin(async move {
361→                let node_id = ctx
362→                    .params
363→                    .get("nodeId")
364→                    .and_then(|v| v.as_str())
365→                    .ok_or_else(|| ErrorShape::new(error_codes::INVALID_REQUEST, "missing nodeId"))?
366→                    .to_string();
367→                let command = ctx
368→                    .params
369→                    .get("command")
370→                    .and_then(|v| v.as_str())
371→                    .ok_or_else(|| {
372→                        ErrorShape::new(error_codes::INVALID_REQUEST, "missing command")
373→                    })?
374→                    .to_string();
375→                let args = ctx
376→                    .params
377→                    .get("args")
378→                    .cloned()
379→                    .unwrap_or(serde_json::json!({}));
380→
381→                // Find the node's conn_id and send the invoke request.
382→                let invoke_id = uuid::Uuid::new_v4().to_string();
383→                let conn_id = {
384→                    let inner = ctx.state.inner.read().await;
385→                    let node = inner.nodes.get(&node_id).ok_or_else(|| {
386→                        ErrorShape::new(error_codes::UNAVAILABLE, "node not connected")
387→                    })?;
388→                    node.conn_id.clone()
389→                };
390→
391→                // Send invoke event to the node.
392→                let invoke_event = moltis_protocol::EventFrame::new(
393→                    "node.invoke.request",
394→                    serde_json::json!({
395→                        "invokeId": invoke_id,
396→                        "command": command,
397→                        "args": args,
398→                    }),
399→                    ctx.state.next_seq(),
400→                );
401→                let event_json = serde_json::to_string(&invoke_event)
402→                    .map_err(|e| ErrorShape::new(error_codes::INVALID_REQUEST, e.to_string()))?;
403→
404→                {
405→                    let inner = ctx.state.inner.read().await;
406→                    let node_client = inner.clients.get(&conn_id).ok_or_else(|| {
407→                        ErrorShape::new(error_codes::UNAVAILABLE, "node connection lost")
408→                    })?;
409→                    if !node_client.send(&event_json) {
410→                        return Err(ErrorShape::new(
411→                            error_codes::UNAVAILABLE,
412→                            "node send failed",
413→                        ));
414→                    }
415→                }
416→
417→                // Set up a oneshot for the result with a timeout.
418→                let (tx, rx) = tokio::sync::oneshot::channel();
419→                {
420→                    let mut inner = ctx.state.inner.write().await;
421→                    inner
422→                        .pending_invokes
423→                        .insert(invoke_id.clone(), crate::state::PendingInvoke {
424→                            request_id: ctx.request_id.clone(),
425→                            sender: tx,
426→                            created_at: std::time::Instant::now(),
427→                        });
428→                }
429→
430→                // Wait for result with 30s timeout.
431→                match tokio::time::timeout(Duration::from_secs(30), rx).await {
432→                    Ok(Ok(result)) => Ok(result),
433→                    Ok(Err(_)) => Err(ErrorShape::new(
434→                        error_codes::UNAVAILABLE,
435→                        "invoke cancelled",
436→                    )),
437→                    Err(_) => {
438→                        ctx.state
439→                            .inner
440→                            .write()
441→                            .await
442→                            .pending_invokes
443→                            .remove(&invoke_id);
444→                        Err(ErrorShape::new(
445→                            error_codes::AGENT_TIMEOUT,
446→                            "node invoke timeout",
447→                        ))
448→                    },
449→                }
450→            })
451→        }),
452→    );
453→
454→    // node.invoke.result: node returns the result of an invoke
455→    reg.register(
456→        "node.invoke.result",
457→        Box::new(|ctx| {
458→            Box::pin(async move {
459→                let invoke_id = ctx
460→                    .params
461→                    .get("invokeId")
462→                    .and_then(|v| v.as_str())
463→                    .ok_or_else(|| {
464→                        ErrorShape::new(error_codes::INVALID_REQUEST, "missing invokeId")
465→                    })?;
466→                let result = ctx
467→                    .params
468→                    .get("result")
469→                    .cloned()
470→                    .unwrap_or(serde_json::json!(null));
471→
472→                let pending = ctx
473→                    .state
474→                    .inner
475→                    .write()
476→                    .await
477→                    .pending_invokes
478→                    .remove(invoke_id);
479→                if let Some(invoke) = pending {
480→                    let _ = invoke.sender.send(result);
481→                    Ok(serde_json::json!({}))
482→                } else {
483→                    Err(ErrorShape::new(
484→                        error_codes::INVALID_REQUEST,
485→                        "no pending invoke for this id",
486→                    ))
487→                }
488→            })
489→        }),
490→    );
491→
492→    // node.event: node broadcasts an event to operator clients
493→    reg.register(
494→        "node.event",
495→        Box::new(|ctx| {
496→            Box::pin(async move {
497→                let event = ctx
498→                    .params
499→                    .get("event")
500→                    .and_then(|v| v.as_str())
501→                    .unwrap_or("node.event");
502→                let payload = ctx
503→                    .params
504→                    .get("payload")
505→                    .cloned()
506→                    .unwrap_or(serde_json::json!({}));
507→
508→                // Intercept telemetry events to cache data in NodeSession.
509→                if event == "node.telemetry"
510→                    && let Some(node_id) = payload.get("nodeId").and_then(|v| v.as_str())
511→                {
512→                    let mem_total = payload
513→                        .get("mem")
514→                        .and_then(|m| m.get("total"))
515→                        .and_then(|v| v.as_u64());
516→                    let mem_available = payload
517→                        .get("mem")
518→                        .and_then(|m| m.get("available"))
519→                        .and_then(|v| v.as_u64());
520→                    let cpu_count = payload
521→                        .get("cpuCount")
522→                        .and_then(|v| v.as_u64())
523→                        .map(|v| v as u32);
524→                    let cpu_usage = payload
525→                        .get("cpuUsage")
526→                        .and_then(|v| v.as_f64())
527→                        .map(|v| v as f32);
528→                    let uptime_secs = payload.get("uptime").and_then(|v| v.as_u64());
529→                    let services: Vec<String> = payload
530→                        .get("services")
531→                        .and_then(|v| v.as_array())
532→                        .map(|arr| {
533→                            arr.iter()
534→                                .filter_map(|v| v.as_str().map(String::from))
535→                                .collect()
536→                        })
537→                        .unwrap_or_default();
538→                    let disk_total = payload
539→                        .get("disk")
540→                        .and_then(|d| d.get("total"))
541→                        .and_then(|v| v.as_u64());
542→                    let disk_available = payload
543→                        .get("disk")
544→                        .and_then(|d| d.get("available"))
545→                        .and_then(|v| v.as_u64());
546→                    let runtimes: Vec<String> = payload
547→                        .get("runtimes")
548→                        .and_then(|v| v.as_array())
549→                        .map(|arr| {
550→                            arr.iter()
551→                                .filter_map(|v| v.as_str().map(String::from))
552→                                .collect()
553→                        })
554→                        .unwrap_or_default();
555→
556→                    let mut inner = ctx.state.inner.write().await;
557→                    let _ = inner.nodes.update_telemetry(
558→                        node_id,
559→                        mem_total,
560→                        mem_available,
561→                        cpu_count,
562→                        cpu_usage,
563→                        uptime_secs,
564→                        services,
565→                        disk_total,
566→                        disk_available,
567→                        runtimes,
568→                    );
569→                }
570→
571→                broadcast(&ctx.state, event, payload, BroadcastOpts::default()).await;
572→                Ok(serde_json::json!({}))
573→            })
574→        }),
575→    );
576→
577→    // location.result: browser returns the result of a geolocation request
578→    reg.register(
579→        "location.result",
580→        Box::new(|ctx| {
581→            Box::pin(async move {
582→                let request_id = ctx
583→                    .params
584→                    .get("requestId")
585→                    .and_then(|v| v.as_str())
586→                    .ok_or_else(|| {
587→                        ErrorShape::new(error_codes::INVALID_REQUEST, "missing requestId")
588→                    })?;
589→
590→                // Build the result value to send through the pending invoke channel.
591→                let result = if let Some(loc) = ctx.params.get("location") {
592→                    // Success: cache the location and persist to USER.md.
593→                    if let (Some(lat), Some(lon)) = (
594→                        loc.get("latitude").and_then(|v| v.as_f64()),
595→                        loc.get("longitude").and_then(|v| v.as_f64()),
596→                    ) {
597→                        let geo = moltis_config::GeoLocation::now(lat, lon, None);
598→                        ctx.state.inner.write().await.cached_location = Some(geo.clone());
599→
600→                        // Persist to USER.md (best-effort).
601→                        let mut user = moltis_config::load_user().unwrap_or_default();
602→                        user.location = Some(geo);
603→                        if let Err(e) = moltis_config::save_user(&user) {
604→                            tracing::warn!(error = %e, "failed to persist location to USER.md");
605→                        }
606→                    }
607→                    serde_json::json!({ "location": ctx.params.get("location") })
608→                } else {
609→                    // Error (permission denied, timeout, etc.)
610→                    serde_json::json!({ "error": ctx.params.get("error") })
611→                };
612→
613→                let pending = ctx
614→                    .state
615→                    .inner
616→                    .write()
617→                    .await
618→                    .pending_invokes
619→                    .remove(request_id);
620→                if let Some(invoke) = pending {
621→                    let _ = invoke.sender.send(result);
622→                    Ok(serde_json::json!({}))
623→                } else {
624→                    Err(ErrorShape::new(
625→                        error_codes::INVALID_REQUEST,
626→                        "no pending location request for this id",
627→                    ))
628→                }
629→            })
630→        }),
631→    );
632→}
