  1→//! Agent-callable tools for querying and selecting remote nodes.
  2→//!
  3→//! Provides `nodes_list`, `nodes_describe`, and `nodes_select` tools that let
  4→//! the agent programmatically interact with connected device nodes.
  5→
  6→use std::sync::Arc;
  7→
  8→use {
  9→    async_trait::async_trait,
 10→    serde::{Deserialize, Serialize},
 11→};
 12→
 13→use moltis_agents::tool_registry::AgentTool;
 14→
 15→// ── Domain types ────────────────────────────────────────────────────────────
 16→
 17→/// Serializable summary of a connected node, returned by the list/describe tools.
 18→#[derive(Debug, Clone, Serialize, Deserialize)]
 19→#[serde(rename_all = "camelCase")]
 20→pub struct NodeInfo {
 21→    pub node_id: String,
 22→    pub display_name: Option<String>,
 23→    pub platform: String,
 24→    pub capabilities: Vec<String>,
 25→    pub commands: Vec<String>,
 26→    #[serde(skip_serializing_if = "Option::is_none")]
 27→    pub remote_ip: Option<String>,
 28→    // Telemetry
 29→    #[serde(skip_serializing_if = "Option::is_none")]
 30→    pub mem_total: Option<u64>,
 31→    #[serde(skip_serializing_if = "Option::is_none")]
 32→    pub mem_available: Option<u64>,
 33→    #[serde(skip_serializing_if = "Option::is_none")]
 34→    pub cpu_count: Option<u32>,
 35→    #[serde(skip_serializing_if = "Option::is_none")]
 36→    pub cpu_usage: Option<f32>,
 37→    #[serde(skip_serializing_if = "Option::is_none")]
 38→    pub uptime_secs: Option<u64>,
 39→    pub services: Vec<String>,
 40→    pub telemetry_stale: bool,
 41→    // P1 fields (populated when provider discovery / richer telemetry lands)
 42→    #[serde(skip_serializing_if = "Option::is_none")]
 43→    pub disk_total: Option<u64>,
 44→    #[serde(skip_serializing_if = "Option::is_none")]
 45→    pub disk_available: Option<u64>,
 46→    #[serde(default, skip_serializing_if = "Vec::is_empty")]
 47→    pub runtimes: Vec<String>,
 48→    #[serde(default, skip_serializing_if = "Vec::is_empty")]
 49→    pub providers: Vec<NodeProviderInfo>,
 50→}
 51→
 52→/// A provider discovered on a remote node (e.g. ollama, openai env key).
 53→#[derive(Debug, Clone, Serialize, Deserialize)]
 54→pub struct NodeProviderInfo {
 55→    pub provider: String,
 56→    #[serde(default, skip_serializing_if = "Vec::is_empty")]
 57→    pub models: Vec<String>,
 58→}
 59→
 60→// ── Provider trait ──────────────────────────────────────────────────────────
 61→
 62→/// Abstraction that the gateway implements to supply node data to the tools
 63→/// crate without a direct dependency.
 64→///
 65→/// Follows the same pattern as [`crate::exec::NodeExecProvider`].
 66→#[async_trait]
 67→pub trait NodeInfoProvider: Send + Sync {
 68→    /// List all currently connected nodes.
 69→    async fn list_nodes(&self) -> Vec<NodeInfo>;
 70→
 71→    /// Describe a single node by id or display name.
 72→    async fn describe_node(&self, node_ref: &str) -> Option<NodeInfo>;
 73→
 74→    /// Assign (or clear) a node for a chat session.
 75→    /// `node_ref` is an id or display name; `None` clears the assignment.
 76→    async fn set_session_node(
 77→        &self,
 78→        session_key: &str,
 79→        node_ref: Option<&str>,
 80→    ) -> anyhow::Result<Option<String>>;
 81→
 82→    /// Resolve a node reference (id or display name) to a canonical node_id.
 83→    async fn resolve_node_id(&self, node_ref: &str) -> Option<String>;
 84→}
 85→
 86→// ── NodesListTool ───────────────────────────────────────────────────────────
 87→
 88→pub struct NodesListTool {
 89→    provider: Arc<dyn NodeInfoProvider>,
 90→}
 91→
 92→impl NodesListTool {
 93→    pub fn new(provider: Arc<dyn NodeInfoProvider>) -> Self {
 94→        Self { provider }
 95→    }
 96→}
 97→
 98→#[async_trait]
 99→impl AgentTool for NodesListTool {
100→    fn name(&self) -> &str {
101→        "nodes_list"
102→    }
103→
104→    fn description(&self) -> &str {
105→        "List all connected remote device nodes with their platform, capabilities, and telemetry."
106→    }
107→
108→    fn parameters_schema(&self) -> serde_json::Value {
109→        serde_json::json!({
110→            "type": "object",
111→            "properties": {},
112→            "additionalProperties": false,
113→        })
114→    }
115→
116→    async fn execute(&self, _params: serde_json::Value) -> anyhow::Result<serde_json::Value> {
117→        let nodes = self.provider.list_nodes().await;
118→        Ok(serde_json::to_value(&nodes)?)
119→    }
120→}
121→
122→// ── NodesDescribeTool ───────────────────────────────────────────────────────
123→
124→pub struct NodesDescribeTool {
125→    provider: Arc<dyn NodeInfoProvider>,
126→}
127→
128→impl NodesDescribeTool {
129→    pub fn new(provider: Arc<dyn NodeInfoProvider>) -> Self {
130→        Self { provider }
131→    }
132→}
133→
134→#[async_trait]
135→impl AgentTool for NodesDescribeTool {
136→    fn name(&self) -> &str {
137→        "nodes_describe"
138→    }
139→
140→    fn description(&self) -> &str {
141→        "Get detailed information about a specific connected node by id or name."
142→    }
143→
144→    fn parameters_schema(&self) -> serde_json::Value {
145→        serde_json::json!({
146→            "type": "object",
147→            "properties": {
148→                "node": {
149→                    "type": "string",
150→                    "description": "Node id or display name",
151→                },
152→            },
153→            "required": ["node"],
154→            "additionalProperties": false,
155→        })
156→    }
157→
158→    async fn execute(&self, params: serde_json::Value) -> anyhow::Result<serde_json::Value> {
159→        let node_ref = params
160→            .get("node")
161→            .and_then(|v| v.as_str())
162→            .ok_or_else(|| anyhow::anyhow!("missing required parameter 'node'"))?;
163→
164→        match self.provider.describe_node(node_ref).await {
165→            Some(info) => Ok(serde_json::to_value(&info)?),
166→            None => Ok(serde_json::json!({ "error": format!("node '{}' not found", node_ref) })),
167→        }
168→    }
169→}
