171→// ── NodesSelectTool ─────────────────────────────────────────────────────────
172→
173→pub struct NodesSelectTool {
174→    provider: Arc<dyn NodeInfoProvider>,
175→}
176→
177→impl NodesSelectTool {
178→    pub fn new(provider: Arc<dyn NodeInfoProvider>) -> Self {
179→        Self { provider }
180→    }
181→}
182→
183→#[async_trait]
184→impl AgentTool for NodesSelectTool {
185→    fn name(&self) -> &str {
186→        "nodes_select"
187→    }
188→
189→    fn description(&self) -> &str {
190→        "Set or clear the default remote node for the current chat session. \
191→         Pass a node id or name to target it, or null/omit to revert to local execution."
192→    }
193→
194→    fn parameters_schema(&self) -> serde_json::Value {
195→        serde_json::json!({
196→            "type": "object",
197→            "properties": {
198→                "node": {
199→                    "type": ["string", "null"],
200→                    "description": "Node id or display name, or null to clear",
201→                },
202→                "_session_key": {
203→                    "type": "string",
204→                    "description": "Session key (injected by the runtime)",
205→                },
206→            },
207→            "additionalProperties": false,
208→        })
209→    }
210→
211→    async fn execute(&self, params: serde_json::Value) -> anyhow::Result<serde_json::Value> {
212→        let session_key = params
213→            .get("_session_key")
214→            .and_then(|v| v.as_str())
215→            .ok_or_else(|| anyhow::anyhow!("missing '_session_key' in tool context"))?;
216→
217→        let node_ref = params.get("node").and_then(|v| v.as_str());
218→
219→        let resolved = self
220→            .provider
221→            .set_session_node(session_key, node_ref)
222→            .await?;
223→
224→        Ok(serde_json::json!({
225→            "ok": true,
226→            "node_id": resolved,
227→        }))
228→    }
229→}
