27→/// Public branding payload for unauthenticated discovery clients.
28→pub async fn api_public_identity_handler(State(state): State<AppState>) -> impl IntoResponse {
29→    let identity: moltis_config::ResolvedIdentity = state
30→        .gateway
31→        .services
32→        .onboarding
33→        .identity_get()
34→        .await
35→        .ok()
36→        .and_then(|value| serde_json::from_value(value).ok())
37→        .unwrap_or_default();
38→
39→    let name = {
40→        let trimmed = identity.name.trim();
41→        if trimmed.is_empty() {
42→            "moltis".to_owned()
43→        } else {
44→            trimmed.to_owned()
45→        }
46→    };
47→
48→    let emoji = identity.emoji.and_then(|raw| {
49→        let trimmed = raw.trim().to_owned();
50→        if trimmed.is_empty() {
51→            None
52→        } else {
53→            Some(trimmed)
54→        }
55→    });
56→
57→    #[cfg(feature = "graphql")]
58→    let graphql_enabled = state.gateway.is_graphql_enabled();
59→    #[cfg(not(feature = "graphql"))]
60→    let graphql_enabled = false;
61→
62→    Json(PublicIdentityPayload {
63→        identity: PublicIdentity { name, emoji },
64→        graphql_enabled,
65→    })
66→}
