 34→function isSshTargetNode(node) {
 35→	return node?.platform === "ssh" || String(node?.nodeId || "").startsWith("ssh:");
 36→}
 37→
 38→function sshTargetValue(node) {
 39→	if (!node) return "";
 40→	if (String(node.nodeId || "").startsWith("ssh:")) {
 41→		return String(node.nodeId).slice(4);
 42→	}
 43→	return String(node.displayName || "")
 44→		.replace(/^SSH:\s*/i, "")
 45→		.trim();
 46→}
 47→
 48→function nodeDisplayLabel(node) {
 49→	if (!node) return "Local";
 50→	if (isSshTargetNode(node)) {
 51→		var target = sshTargetValue(node);
 52→		return target ? `SSH: ${target}` : node.displayName || node.nodeId;
 53→	}
 54→	return node.displayName || node.nodeId;
 55→}
