 57→function gatewayWsUrl() {
 58→	var proto = location.protocol === "https:" ? "wss:" : "ws:";
 59→	var port = gon.get("port") || location.port;
 60→	var host = location.hostname;
 61→	return `${proto}//${host}${port ? `:${port}` : ""}/ws`;
