166→async function repairActiveRouteHostPin() {
167→	var snapshot = doctor.value;
168→	var activeRoute = snapshot?.active_route || null;
169→	if (!activeRoute?.target_id) {
170→		showToast("The active SSH route cannot be managed from the doctor panel", "error");
171→		return;
172→	}
173→
174→	doctorPinLoading.value = true;
175→	doctorError.value = "";
176→	try {
177→		var scanResponse = await fetch("/api/ssh/host-key/scan", {
178→			method: "POST",
179→			headers: { "Content-Type": "application/json" },
180→			body: JSON.stringify({
181→				target: activeRoute.target,
182→				port: activeRoute.port ?? null,
183→			}),
184→		});
185→		var scanData = await scanResponse.json();
186→		if (!scanResponse.ok) {
187→			throw new Error(scanData?.error || "Failed to scan SSH host key");
188→		}
189→
190→		var pinResponse = await fetch(`/api/ssh/targets/${activeRoute.target_id}/pin`, {
191→			method: "POST",
192→			headers: { "Content-Type": "application/json" },
193→			body: JSON.stringify({ known_host: scanData.known_host }),
194→		});
195→		var pinData = await pinResponse.json();
196→		if (!pinResponse.ok) {
197→			throw new Error(pinData?.error || "Failed to pin SSH host key");
198→		}
199→
200→		await refreshDoctor();
201→		showToast(activeRoute.host_pinned ? "Active SSH host pin refreshed" : "Active SSH host pinned", "success");
202→	} catch (error) {
203→		doctorError.value = error.message || "Failed to repair SSH host pin";
204→		showToast(doctorError.value, "error");
205→	} finally {
206→		doctorPinLoading.value = false;
207→	}
208→}
