382→function formatBytes(bytes) {
383→	if (bytes == null) return null;
384→	var gb = bytes / 1073741824;
385→	if (gb >= 1) return `${gb.toFixed(1)} GB`;
386→	var mb = bytes / 1048576;
387→	return `${mb.toFixed(0)} MB`;
388→}
