390→function TelemetryBar({ label, value, max }) {
391→	if (value == null || max == null || max === 0) return null;
392→	var pct = Math.min(100, Math.max(0, (value / max) * 100));
393→	var color = pct > 80 ? "bg-red-500" : pct > 60 ? "bg-yellow-500" : "bg-green-500";
394→	return html`<div class="flex items-center gap-2 text-xs text-[var(--text-muted)]">
395→		<span class="w-8 shrink-0">${label}</span>
396→		<div class="flex-1 h-1.5 rounded bg-[var(--border)] overflow-hidden">
397→			<div class="${color} h-full rounded" style="width:${pct.toFixed(1)}%"></div>
398→		</div>
399→		<span class="w-16 text-right shrink-0">${pct.toFixed(0)}%</span>
400→	</div>`;
401→}
