403→function NodeTelemetry({ telemetry }) {
404→	if (!telemetry) return null;
405→	var parts = [];
406→	if (telemetry.cpuCount != null) {
407→		parts.push(html`<span>${telemetry.cpuCount} cores</span>`);
408→	}
409→	if (telemetry.memTotal != null) {
410→		parts.push(html`<span>${formatBytes(telemetry.memTotal)} RAM</span>`);
411→	}
412→	if (telemetry.uptimeSecs != null) {
413→		var h = Math.floor(telemetry.uptimeSecs / 3600);
414→		var d = Math.floor(h / 24);
415→		var uptimeStr = d > 0 ? `${d}d ${h % 24}h` : `${h}h`;
416→		parts.push(html`<span>up ${uptimeStr}</span>`);
417→	}
418→	if (telemetry.stale) {
419→		parts.push(html`<span class="text-yellow-500">(stale)</span>`);
420→	}
421→
422→	return html`<div class="mt-1.5 flex flex-col gap-1">
423→		${telemetry.cpuUsage != null ? html`<${TelemetryBar} label="CPU" value=${telemetry.cpuUsage} max=${100} />` : null}
424→		${
425→			telemetry.memTotal != null && telemetry.memAvailable != null
426→				? html`<${TelemetryBar}
427→						label="MEM"
428→						value=${telemetry.memTotal - telemetry.memAvailable}
429→						max=${telemetry.memTotal}
430→					/>`
431→				: null
432→		}
433→		${parts.length > 0 ? html`<div class="text-xs text-[var(--text-muted)] flex gap-2 flex-wrap">${parts}</div>` : null}
434→	</div>`;
435→}
