769→function NodesPage() {
770→	useEffect(() => {
771→		refreshAll();
772→
773→		// Subscribe to presence events for live updates.
774→		var unsub = onEvent("presence", () => {
775→			refreshNodes();
776→		});
777→		var unsubPair = onEvent("node.pair.requested", () => {
778→			refreshPendingPairs();
779→		});
780→		var unsubResolved = onEvent("node.pair.resolved", () => {
781→			refreshAll();
782→		});
783→		var unsubDevice = onEvent("device.pair.resolved", () => {
784→			refreshAll();
785→		});
786→		// Live telemetry updates — merge into cached node list.
787→		var unsubTelemetry = onEvent("node.telemetry", (payload) => {
788→			if (!payload?.nodeId) return;
789→			var updated = nodes.value.map((n) => {
790→				if (n.nodeId !== payload.nodeId) return n;
791→				return Object.assign({}, n, {
792→					telemetry: {
793→						memTotal: payload.mem?.total ?? n.telemetry?.memTotal,
794→						memAvailable: payload.mem?.available ?? n.telemetry?.memAvailable,
795→						cpuCount: payload.cpuCount ?? n.telemetry?.cpuCount,
796→						cpuUsage: payload.cpuUsage ?? n.telemetry?.cpuUsage,
797→						uptimeSecs: payload.uptime ?? n.telemetry?.uptimeSecs,
798→						services: payload.services ?? n.telemetry?.services ?? [],
799→						stale: false,
800→					},
801→				});
802→			});
803→			nodes.value = updated;
804→		});
805→
806→		return () => {
807→			unsub();
808→			unsubPair();
809→			unsubResolved();
810→			unsubDevice();
811→			unsubTelemetry();
812→		};
813→	}, []);
814→
815→	return html`<div class="flex-1 flex flex-col min-w-0 p-4 gap-4 overflow-y-auto">
816→		<div class="max-w-form flex flex-col gap-4">
817→			<div>
818→				<div class="flex items-center gap-3 mb-1">
819→					<h2 class="text-lg font-medium text-[var(--text-strong)]">Nodes</h2>
820→					<button
821→						class="provider-btn provider-btn-secondary provider-btn-sm"
822→						onClick=${refreshAll}
823→						disabled=${loading.value}
824→					>
825→						${loading.value ? "Refreshing..." : "Refresh"}
826→					</button>
827→				</div>
828→				<p class="text-xs text-[var(--muted)] leading-relaxed" style="margin:0;">
829→					Nodes are remote execution targets. Paired nodes stream telemetry and
830→					capabilities back to the gateway, while configured SSH targets route
831→					commands through your local OpenSSH setup. The agent can choose where to
832→					run commands based on what is available.
833→				</p>
834→			</div>
835→
836→			<${RemoteExecStatusCard} />
837→
838→			<${TabBar} />
839→
840→			${
841→				activeTab.value === "connected"
842→					? html`<${ConnectedNodesList} />
843→						${nodes.value.length > 0 ? html`<${ConnectNodeForm} />` : null}`
844→					: null
845→			}
846→			${activeTab.value === "paired" ? html`<${PairedDevicesList} />` : null}
847→			${activeTab.value === "pending" ? html`<${PendingPairsList} />` : null}
